create table oehr_departments (
    department_id   number(4, 0) generated by default on null as identity minvalue 1 maxvalue 9990 increment by 10 nocache noorder nocycle
    nokeep noscale not null enable,
    department_name varchar2(30 byte)
        constraint oehr_dept_name_nn not null enable,
    manager_id      number(6, 0),
    location_id     number(4, 0)
);

alter table oehr_departments
    add constraint oehr_dept_id_pk primary key ( department_id )
        using index enable;

